#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N, M, K; scanf("%d %d %d", &N, &M, &K);
        int eligible = 0;
        for(int i=0;i<N;i++){
            long long sum = 0;
            for(int j=0;j<K;j++){
                int t; scanf("%d", &t); sum += t;
            }
            int q; scanf("%d", &q);
            if(sum >= M && q <= 10) eligible++;
        }
        printf("%d\n", eligible);
    }
    return 0;
}

