#!/usr/bin/env python3
import sys

def main():
    data = list(map(int, sys.stdin.read().strip().split()))
    if not data:
        return
    it = iter(data)
    T = next(it)
    out_lines = []
    for _ in range(T):
        N = next(it); M = next(it); K = next(it)
        eligible = 0
        for _ in range(N):
            total = 0
            for _ in range(K):
                total += next(it)
            q = next(it)
            if total >= M and q <= 10:
                eligible += 1
        out_lines.append(str(eligible))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

